@login_required
def admin_upload_logo():
    """Upload logo file and return URL"""
    if not current_user.is_admin:
        abort(403)

    try:
        if 'logo' not in request.files:
            return jsonify({'success': False, 'message': 'لم يتم العثور على ملف'})

        file = request.files['logo']
        if file.filename == '':
            return jsonify({'success': False, 'message': 'لم يتم اختيار ملف'})

        # Validate file type
        allowed_extensions = {'png', 'jpg', 'jpeg', 'svg', 'gif'}
        if '.' not in (file.filename or '') or \
           (file.filename and file.filename.rsplit('.', 1)[1].lower() not in allowed_extensions):
            return jsonify({'success': False, 'message': 'نوع الملف غير مدعوم'})

        # Validate file size (max 5MB)
        if hasattr(file, 'content_length') and file.content_length > 5 * 1024 * 1024:
            return jsonify({'success': False, 'message': 'حجم الملف كبير جداً'})

        # Create uploads directory if it doesn't exist
        upload_dir = os.path.join(app.static_folder or 'static', 'uploads', 'logos')
        os.makedirs(upload_dir, exist_ok=True)

        # Generate unique filename
        import time
        timestamp = str(int(time.time()))
        filename = f"logo_{timestamp}_{file.filename}"
        filepath = os.path.join(upload_dir, filename)

        # Save file
        file.save(filepath)

        # Generate URL
        logo_url = url_for('static', filename=f'uploads/logos/{filename}')

        return jsonify({'success': True, 'url': logo_url})

    except Exception as e:
        import logging
        logging.error(f"Logo upload error: {e}")
        return jsonify({'success': False, 'message': 'حدث خطأ أثناء رفع الملف'})

