            gateway.display_name_ar = display_name
            gateway.gateway_type = 'stripe'

        # Set configuration
        gateway.is_active = is_active
        gateway.is_sandbox = (environment == 'sandbox')
        gateway.is_default = is_default

        if currencies:
            gateway.supported_currencies = currencies
        else:
