def test_database_connection_internal(database_url):
    """Internal function to test database connection"""
    try:
        from sqlalchemy import create_engine, text
        import urllib.parse

        # Parse the database URL to get info
        parsed = urllib.parse.urlparse(database_url)

        # Create test engine
        test_engine = create_engine(database_url, pool_pre_ping=True)

        # Test connection
        with test_engine.connect() as conn:
            # Get PostgreSQL version
            version_result = conn.execute(text("SELECT version()"))
            version = version_result.scalar()

            # Get table count
            tables_result = conn.execute(text("SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = 'public'"))
            tables_count = tables_result.scalar()

            return {
                'success': True,
                'db_type': 'PostgreSQL',
                'version': version.split(' ')[1] if version else 'Unknown',
                'tables_count': tables_count,
                'host': parsed.hostname,
                'port': parsed.port,
                'database': parsed.path.lstrip('/')
            }

    except Exception as e:
        return {
            'success': False,
            'error': str(e)
        }

