}

/* Inter Font Import */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap');

/* Smooth scrolling */
html {
    scroll-behavior: smooth;
    overflow-x: hidden !important;
    max-width: 100vw !important;
}

