/* ===== MODERN HERO SECTION ===== */
.hero-section-modern {
    background: var(--bg-primary);
    border: 1px solid var(--border-color);
    backdrop-filter: blur(10px);
    color: white;
    padding: 5rem 0;
    position: relative;
    overflow: visible;
}

.hero-section-modern::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(135deg, rgba(220, 53, 69, 0.1) 0%, transparent 70%);
    pointer-events: none;
}

/* Dragon Animation Styles */
.dragon-animation-container {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    overflow: hidden;
    pointer-events: none;
    z-index: 1;
}

.flying-dragon {
    position: absolute;
    width: 200px;
    height: 120px;
    opacity: 0.6;
    animation: dragonFlight 25s linear infinite;
    filter: drop-shadow(0 0 10px rgba(220, 53, 69, 0.3));
}

@keyframes dragonFlight {
    0% {
        transform: translateX(-250px) translateY(20%) scale(0.8) rotateY(0deg);
        opacity: 0;
    }
    10% {
        opacity: 0.6;
        transform: translateX(-150px) translateY(15%) scale(0.9) rotateY(5deg);
    }
    25% {
        transform: translateX(20vw) translateY(10%) scale(1) rotateY(0deg);
    }
    40% {
        transform: translateX(40vw) translateY(25%) scale(1.1) rotateY(-8deg);
    }
    55% {
        transform: translateX(60vw) translateY(15%) scale(1) rotateY(3deg);
    }
    70% {
        transform: translateX(80vw) translateY(30%) scale(0.9) rotateY(-5deg);
    }
    85% {
        transform: translateX(calc(100vw + 50px)) translateY(20%) scale(0.8) rotateY(0deg);
        opacity: 0.6;
    }
    100% {
        transform: translateX(calc(100vw + 250px)) translateY(25%) scale(0.7) rotateY(0deg);
        opacity: 0;
    }
}

/* Dragon hover effects on hero section */
.hero-section-modern:hover .flying-dragon {
    animation-duration: 15s;
    opacity: 0.8;
}

/* Dragon Variants */
.dragon-primary {
    animation-duration: 25s;
    opacity: 0.6;
}

.dragon-secondary {
    animation: dragonFlightReverse 30s linear infinite;
    animation-delay: -15s;
    opacity: 0.4;
    transform: scale(0.7);
    top: 60%;
}

.dragon-tertiary {
    animation: dragonFlightSlow 35s linear infinite;
    animation-delay: -25s;
    opacity: 0.3;
    transform: scale(0.5);
    top: 30%;
}

/* Reverse flight animation for variety */
@keyframes dragonFlightReverse {
    0% {
        transform: translateX(calc(100vw + 250px)) translateY(30%) scale(0.7) rotateY(180deg);
        opacity: 0;
    }
    15% {
        opacity: 0.4;
        transform: translateX(80vw) translateY(25%) scale(0.8) rotateY(175deg);
    }
    30% {
        transform: translateX(60vw) translateY(35%) scale(0.9) rotateY(185deg);
    }
    50% {
        transform: translateX(40vw) translateY(20%) scale(1) rotateY(180deg);
    }
    70% {
        transform: translateX(20vw) translateY(40%) scale(0.9) rotateY(175deg);
    }
    85% {
        transform: translateX(-50px) translateY(30%) scale(0.8) rotateY(180deg);
        opacity: 0.4;
    }
    100% {
        transform: translateX(-250px) translateY(35%) scale(0.7) rotateY(180deg);
        opacity: 0;
    }
}

/* Slow curved flight */
@keyframes dragonFlightSlow {
    0% {
        transform: translateX(-250px) translateY(40%) scale(0.5) rotateY(0deg);
        opacity: 0;
    }
    20% {
        opacity: 0.3;
        transform: translateX(25vw) translateY(10%) scale(0.6) rotateY(10deg);
    }
    50% {
        transform: translateX(50vw) translateY(50%) scale(0.7) rotateY(-5deg);
    }
    80% {
        transform: translateX(75vw) translateY(15%) scale(0.6) rotateY(8deg);
        opacity: 0.3;
    }
    100% {
        transform: translateX(calc(100vw + 250px)) translateY(35%) scale(0.5) rotateY(0deg);
        opacity: 0;
    }
}

/* Responsive adjustments */
@media (max-width: 768px) {
    .flying-dragon {
        width: 150px;
        height: 90px;
    }

    .dragon-secondary {
        top: 70%;
    }

    .dragon-tertiary {
        top: 40%;
    }
}

