    font-size: 2rem;
    font-weight: 700;
    color: #ffd700;
    text-shadow: 0 2px 10px rgba(0,0,0,0.3);
}

.stat-label {
    display: block;
    font-size: 0.9rem;
    opacity: 0.8;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.hero-actions {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
}

.btn-hero-primary {
    background: linear-gradient(45deg, #ff6b6b, #ffa726);
    border: none;
    color: white;
    padding: 1rem 2rem;
    border-radius: 50px;
    font-weight: 600;
    font-size: 1.1rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    transition: all 0.3s ease;
    box-shadow: 0 4px 15px rgba(255, 107, 107, 0.4);
}

.btn-hero-primary:hover {
    transform: translateY(-3px);
    box-shadow: 0 8px 25px rgba(255, 107, 107, 0.6);
    color: white;
}

.btn-hero-outline {
    background: transparent;
    border: 2px solid rgba(255, 255, 255, 0.8);
    color: white;
    padding: 1rem 2rem;
    border-radius: 50px;
    font-weight: 600;
    font-size: 1.1rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    transition: all 0.3s ease;
    backdrop-filter: blur(10px);
}

.btn-hero-outline:hover {
    background: rgba(255, 255, 255, 0.1);
    transform: translateY(-3px);
    color: white;
    box-shadow: 0 8px 25px rgba(255, 255, 255, 0.2);
}

/* Featured Manga Showcase */
.hero-visual {
    position: relative;
    z-index: 2;
}

.featured-manga-showcase {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 1rem;
    padding: 2rem;
}

.featured-card {
    position: relative;
    border-radius: 15px;
    overflow: hidden;
    transition: all 0.3s ease;
    box-shadow: 0 10px 30px rgba(0,0,0,0.3);
}

.featured-card:hover {
    transform: translateY(-10px) rotateY(5deg);
    box-shadow: 0 20px 40px rgba(0,0,0,0.4);
}

.featured-cover {
    position: relative;
    aspect-ratio: 3/4;
    overflow: hidden;
}

.featured-cover img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.3s ease;
}

.featured-card:hover .featured-cover img {
    transform: scale(1.1);
}

.placeholder-featured {
    width: 100%;
    height: 100%;
    background: rgba(255, 255, 255, 0.1);
    display: flex;
    align-items: center;
    justify-content: center;
    color: rgba(255, 255, 255, 0.7);
}

.featured-overlay {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    background: linear-gradient(transparent, rgba(0,0,0,0.8));
    padding: 1.5rem;
    transform: translateY(50%);
    transition: all 0.3s ease;
}

.featured-card:hover .featured-overlay {
    transform: translateY(0);
}

.featured-title {
    color: white;
    font-weight: 600;
    margin-bottom: 0.5rem;
    font-size: 0.9rem;
}

.featured-author {
    color: rgba(255, 255, 255, 0.8);
    font-size: 0.8rem;
    margin-bottom: 0.5rem;
}

.featured-stats {
    display: flex;
    gap: 0.5rem;
}

.hero-placeholder {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    height: 400px;
    background: rgba(255, 255, 255, 0.1);
    border-radius: 20px;
    backdrop-filter: blur(10px);
}

/* ===== MODERN MANGA CARDS ===== */
.manga-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 1.5rem;
    margin-top: 2rem;
    overflow-x: hidden;
    max-width: 100%;
}

.manga-card-modern {
    background: var(--bg-secondary) !important;
    border: 1px solid var(--border-color) !important;
    color: var(--text-color) !important;
    border-radius: var(--border-radius-lg);
    overflow: hidden;
    transition: var(--transition);
    backdrop-filter: blur(10px);
    position: relative;
    height: fit-content;
}

.manga-card-modern:hover {
    border-color: var(--primary-color) !important;
    transform: translateY(-5px);
    box-shadow: var(--shadow-lg);
}

.manga-cover-container {
    position: relative;
    aspect-ratio: 3/4;
    overflow: hidden;
    background: var(--bg-tertiary);
}

.manga-cover-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: all 0.3s ease;
}

.manga-card-modern:hover .manga-cover-img {
    transform: scale(1.1);
    filter: brightness(0.9);
}

.manga-cover-placeholder {
    width: 100%;
    height: 100%;
    display: flex;
    align-items: center;
    justify-content: center;
    background: linear-gradient(135deg, #f8f9fa, #e9ecef);
    color: #6c757d;
}

.status-badges {
    position: absolute;
    top: 0.75rem;
    right: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    z-index: 2;
}

.badge {
    font-size: 0.75rem;
    padding: 0.25rem 0.5rem;
    border-radius: 20px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.badge-premium {
    background: linear-gradient(45deg, #ffd700, #ffb347);
    color: #333;
    box-shadow: 0 2px 10px rgba(255, 215, 0, 0.3);
}

.badge-ongoing {
    background: #28a745;
    color: white;
}

.badge-completed {
    background: #007bff;
    color: white;
}

.badge-popular {
    background: linear-gradient(45deg, #ff6b6b, #ffa726);
    color: white;
    animation: pulse 2s infinite;
}

.badge-new {
    background: #28a745;
    color: white;
    position: relative;
}

.badge-new::before {
    content: '';
    position: absolute;
    top: -2px;
    left: -2px;
    right: -2px;
    bottom: -2px;
    background: linear-gradient(45deg, #28a745, #20c997);
    border-radius: 20px;
    z-index: -1;
    animation: glow 1.5s ease-in-out infinite alternate;
}

@keyframes glow {
    from { box-shadow: 0 0 5px #28a745; }
    to { box-shadow: 0 0 15px #28a745; }
}

.manga-hover-overlay {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(to bottom, transparent 0%, rgba(0,0,0,0.8) 100%);
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    padding: 1rem;
    opacity: 0;
    transition: all 0.3s ease;
    z-index: 1;
}

.manga-card-modern:hover .manga-hover-overlay {
    opacity: 1;
}

.manga-quick-info {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
}

.rating-display,
.views-display {
    display: flex;
    align-items: center;
    gap: 0.25rem;
    background: rgba(0,0,0,0.7);
    padding: 0.25rem 0.5rem;
    border-radius: 15px;
    color: white;
    font-size: 0.8rem;
    backdrop-filter: blur(5px);
}

.type-display {
    margin-left: auto;
}

.type-badge {
    padding: 0.25rem 0.75rem;
    border-radius: 15px;
    font-size: 0.7rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.type-manga { background: #007bff; color: white; }
.type-manhwa { background: #28a745; color: white; }
.type-manhua { background: #ffc107; color: #333; }

.quick-actions {
    display: flex;
    justify-content: center;
    gap: 0.5rem;
    margin-top: auto;
}

.btn-quick-action {
    background: rgba(255,255,255,0.2);
    border: 1px solid rgba(255,255,255,0.3);
    color: white;
    border-radius: 50%;
    width: 40px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.3s ease;
    backdrop-filter: blur(5px);
}

.btn-quick-action:hover {
    background: rgba(255,255,255,0.4);
    color: white;
    transform: scale(1.1);
}

.manga-info {
    padding: 1rem;
}

.manga-title {
    font-weight: 600;
    font-size: 0.95rem;
    margin-bottom: 0.5rem;
    color: var(--text-color);
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
    line-height: 1.4;
}

.manga-author {
    color: var(--text-muted);
    font-size: 0.85rem;
    margin-bottom: 0.75rem;
    display: -webkit-box;
    -webkit-line-clamp: 1;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.manga-meta {
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-size: 0.8rem;
}

.chapters-count {
    display: flex;
    align-items: center;
    gap: 0.25rem;
    color: var(--text-muted);
}

.type-badge-small {
    padding: 0.2rem 0.5rem;
    border-radius: 10px;
    font-size: 0.65rem;
    font-weight: 600;
    text-transform: uppercase;
}

.update-time {
    font-size: 0.75rem;
}

.manga-cover-wrapper {
    position: relative;
    overflow: hidden;
    border-radius: var(--border-radius) var(--border-radius) 0 0;
}

.manga-cover {
    width: 100%;
    height: 300px;
    object-fit: cover;
    transition: var(--transition);
}

.placeholder-cover {
    width: 100%;
    height: 300px;
    background: var(--light-color);
    border: 2px dashed #dee2e6;
}

.placeholder-cover-large {
    width: 100%;
    height: 500px;
    background: var(--light-color);
    border: 2px dashed #dee2e6;
}

.manga-overlay {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(to bottom, transparent, rgba(0,0,0,0.7));
    opacity: 0;
    transition: var(--transition);
    display: flex;
    align-items: flex-end;
    padding: 1rem;
}

.manga-card:hover .manga-overlay {
    opacity: 1;
}

.manga-stats {
    display: flex;
    gap: 0.5rem;
}

.manga-stats .badge {
    font-size: 0.8rem;
}

/* ===== LOGIN PAGE LOGO ===== */
.login-logo {
    max-height: 80px;
    max-width: 200px;
    object-fit: contain;
    filter: drop-shadow(0 4px 8px rgba(0,0,0,0.3));
}

/* ===== LOCKED CHAPTERS ===== */
.locked-chapter {
    background: rgba(255, 193, 7, 0.1);
    border-left: 4px solid #ffc107;
}

.locked-chapter .chapter-link {
    opacity: 0.8;
}

.locked-chapter:hover {
    background: rgba(255, 193, 7, 0.15);
}

/* ===== MODERN SECTIONS ===== */
.content-section {
    position: relative;
}

.section-header {
    margin-bottom: 2rem;
}

.section-title {
    font-size: 2.5rem;
    font-weight: 700;
    color: #333;
    margin-bottom: 0.5rem;
    display: flex;
    align-items: center;
}

.section-subtitle {
    color: #6c757d;
    font-size: 1.1rem;
    margin-bottom: 0;
}

.btn-modern-outline {
    background: transparent;
    border: 2px solid #007bff;
    color: #007bff;
    padding: 0.75rem 1.5rem;
    border-radius: 25px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    transition: all 0.3s ease;
    font-size: 0.9rem;
}

.btn-modern-outline:hover {
    background: #007bff;
    color: white;
    transform: translateY(-2px);
    box-shadow: 0 8px 25px rgba(0, 123, 255, 0.3);
}

.bg-gradient-light {
    background: linear-gradient(135deg, #f8f9fa 0%, #ffffff 50%, #f1f3f4 100%);
}

/* Categories Quick Bar */
.categories-quick-bar {
    border-bottom: 1px solid var(--border-color);
    background: var(--bg-secondary);
    box-shadow: var(--shadow-md);
    backdrop-filter: blur(10px);
}

.categories-quick-bar .col-lg-2 h6 {
    font-size: 0.8rem !important;
    margin-bottom: 0 !important;
}

/* Favorites heart icon styling */
.btn-outline-light .fa-heart {
    color: #dc3545 !important;
    transition: all 0.3s ease;
}

.btn-outline-light:hover .fa-heart {
    color: #ff6b6b !important;
    transform: scale(1.1);
}

.nav-link .fa-heart {
    color: #dc3545 !important;
}

.categories-scroll {
    scrollbar-width: none;
    -ms-overflow-style: none;
}

.categories-scroll::-webkit-scrollbar {
    display: none;
}

.category-chip {
    display: inline-flex;
    align-items: center;
    padding: 0.3rem 0.7rem;
    background: var(--bg-tertiary);
    color: var(--text-color);
    border-radius: 20px;
    text-decoration: none;
    font-weight: 500;
    font-size: 0.8rem;
    border: 1px solid var(--border-color);
    transition: all 0.3s ease;
    white-space: nowrap;
}

.category-chip:hover {
    background: var(--primary-color);
    color: white;
    border-color: var(--primary-color);
    transform: translateY(-2px);
    text-decoration: none;
    box-shadow: var(--shadow-lg);
}

.category-chip-more {
    display: inline-flex;
    align-items: center;
    padding: 0.3rem 0.7rem;
    background: linear-gradient(45deg, #dc3545, #ff6b35, #f7931e);
    color: white;
    border-radius: 20px;
    text-decoration: none;
    font-weight: 600;
    font-size: 0.8rem;
    transition: all 0.3s ease;
    white-space: nowrap;
    box-shadow: 0 4px 15px rgba(220, 53, 69, 0.3), 0 2px 8px rgba(255, 107, 53, 0.2);
}

.category-chip-more:hover {
    color: white;
    transform: translateY(-2px) scale(1.05);
    box-shadow: 0 8px 25px rgba(220, 53, 69, 0.4), 0 4px 12px rgba(255, 107, 53, 0.3);
    text-decoration: none;
}

/* Trending Showcase */
.trending-showcase {
    position: relative;
    overflow-x: hidden;
    max-width: 100%;
}

.top-three-grid {
    display: grid;
    grid-template-columns: 1fr 1fr 1fr;
    gap: 2rem;
    margin-bottom: 3rem;
    overflow-x: hidden;
    max-width: 100%;
}

.top-manga-card {
    position: relative;
    border-radius: 20px;
    overflow: hidden;
    background: white;
    box-shadow: 0 10px 30px rgba(0,0,0,0.1);
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.top-manga-card:hover {
    transform: translateY(-10px) rotateY(2deg);
    box-shadow: 0 20px 60px rgba(0,0,0,0.2);
}

.rank-badge {
    position: absolute;
    top: -15px;
    left: 20px;
    z-index: 3;
}

.rank-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 40px;
    height: 40px;
    border-radius: 50%;
    font-weight: 700;
    font-size: 1.2rem;
    color: white;
    text-shadow: 0 2px 4px rgba(0,0,0,0.3);
}

.rank-1 .rank-number {
    background: linear-gradient(45deg, #ffd700, #ffed4e);
    box-shadow: 0 4px 20px rgba(255, 215, 0, 0.4);
}

.rank-2 .rank-number {
    background: linear-gradient(45deg, #c0c0c0, #e8e8e8);
    color: #333;
    box-shadow: 0 4px 20px rgba(192, 192, 192, 0.4);
}

.rank-3 .rank-number {
    background: linear-gradient(45deg, #cd7f32, #d4a574);
    box-shadow: 0 4px 20px rgba(205, 127, 50, 0.4);
}

.top-manga-cover {
    position: relative;
    aspect-ratio: 3/4;
    overflow: hidden;
}

.top-manga-cover img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.3s ease;
}

.top-manga-card:hover .top-manga-cover img {
    transform: scale(1.1);
}

.placeholder-top {
    width: 100%;
    height: 100%;
    background: linear-gradient(135deg, #f8f9fa, #e9ecef);
    display: flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
}

.top-manga-gradient {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 50%;
    background: linear-gradient(to top, rgba(0,0,0,0.8), transparent);
}

.top-manga-info {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    padding: 1.5rem;
    color: white;
    z-index: 2;
}

.top-manga-title {
    font-size: 1.1rem;
    font-weight: 700;
    margin-bottom: 0.5rem;
    text-shadow: 0 2px 4px rgba(0,0,0,0.3);
}

.top-manga-author {
    font-size: 0.9rem;
    opacity: 0.9;
    margin-bottom: 1rem;
}

.top-manga-stats {
    display: flex;
    gap: 1rem;
    align-items: center;
}

.top-manga-stats .stat-item {
    display: flex;
    align-items: center;
    gap: 0.25rem;
    font-size: 0.8rem;
    background: rgba(255,255,255,0.2);
    padding: 0.25rem 0.5rem;
    border-radius: 15px;
    backdrop-filter: blur(5px);
}

/* Mini Sections */
.dual-sections {
    background: var(--bg-primary);
}

.mini-section {
    background: var(--bg-secondary);
    border: 1px solid var(--border-color);
    border-radius: 15px;
    padding: 1.5rem;
    height: 100%;
    box-shadow: var(--shadow-md);
    backdrop-filter: blur(10px);
}

.mini-section-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
