.mobile-search-bar {
    background: linear-gradient(135deg, var(--bg-secondary) 0%, rgba(36, 36, 36, 0.98) 50%, var(--bg-primary) 100%);
    position: fixed;
    top: 60px;
    left: 15px;
    right: 15px;
    z-index: 999999;
    box-shadow: 0 15px 40px rgba(0, 0, 0, 0.9), 0 8px 25px rgba(220, 53, 69, 0.15);
