    opacity: 1 !important;
    visibility: visible !important;
    transform: translateY(0) scale(1) !important;
    animation: searchBarEntrance 0.6s cubic-bezier(0.34, 1.56, 0.64, 1);

    /* Enable interaction when visible */
    pointer-events: auto !important;
