        display: none !important;
    }
}

/* Mobile Notifications */
.mobile-notifications {
    width: 280px !important;
    max-height: 300px !important;
}

/* Desktop Controls - Desktop Only */
@media (min-width: 992px) {
    .desktop-controls .btn {
        width: 45px;
        height: 45px;
        display: flex;
        align-items: center;
        justify-content: center;
        border-radius: 50%;
        transition: all 0.3s ease;
        background: rgba(255, 255, 255, 0.1);
        backdrop-filter: blur(10px);
    }

    .desktop-controls .btn:hover {
        transform: scale(1.1);
        box-shadow: 0 4px 15px rgba(255, 255, 255, 0.2);
        background: rgba(255, 255, 255, 0.2);
    }
}

/* RTL Support */
[dir="rtl"] .mobile-nav-grid {
    direction: rtl;
}

[dir="rtl"] .modern-nav-link,
[dir="rtl"] .modern-control-btn {
    text-align: center;
}

/* Dark Mode Adjustments */
[data-theme="dark"] .modern-navbar {
    background: linear-gradient(135deg, #1a202c, #0d1117) !important;
}

[data-theme="dark"] .modern-collapse {
    background: rgba(26, 32, 44, 0.95);
}

[data-theme="dark"] .modern-nav-link,
[data-theme="dark"] .modern-control-btn {
    background: rgba(255, 255, 255, 0.03);
}

[data-theme="dark"] .modern-nav-link:hover,
[data-theme="dark"] .modern-control-btn:hover {
    background: rgba(255, 255, 255, 0.1);
}

/* Animation for navbar collapse */
.navbar-collapse {
    transition: all 0.3s ease-in-out;
}

.navbar-collapse.show {
    animation: fadeInDown 0.3s ease-out;
}

@keyframes fadeInDown {
    from {
        opacity: 0;
        transform: translateY(-20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* ===== ADMIN DROPDOWN SCROLLBAR FIX ===== */
/* Fix dropdown to appear outside navbar container */
.navbar-nav .nav-item.dropdown {
    position: static !important;
}

.navbar .container {
    overflow: visible !important;
    position: relative !important;
}

.navbar-collapse {
    overflow: visible !important;
}

/* Remove scrollbar from admin/user dropdown menu in desktop view */
@media (min-width: 992px) {
    .admin-user-dropdown,
    .modern-dropdown {
        max-height: none !important;
        overflow-y: visible !important;
        overflow-x: visible !important;
        height: auto !important;
        position: absolute !important;
        z-index: 1040 !important;
    }

    /* Ensure admin dropdown content shows without scrolling */
    .admin-user-dropdown .admin-actions,
    .admin-user-dropdown .dropdown-item-group,
    .modern-dropdown .admin-actions,
    .modern-dropdown .dropdown-item-group {
        overflow: visible !important;
        max-height: none !important;
    }

    /* Specifically target user dropdown in navbar to remove scrollbar */
    .navbar-nav .nav-item.dropdown .dropdown-menu {
        max-height: none !important;
        overflow-y: visible !important;
        overflow-x: visible !important;
        position: absolute !important;
        z-index: 1040 !important;
    }

    /* Target the specific admin user dropdown by ID */
    #adminUserDropdown {
        max-height: none !important;
        overflow-y: visible !important;
        overflow-x: visible !important;
        height: auto !important;
        position: absolute !important;
        z-index: 1040 !important;
    }

    /* Ensure navbar doesn't clip dropdown */
    .navbar,
    .navbar-nav,
    .navbar-collapse,
    .navbar .container,
    .navbar .container-fluid {
        overflow: visible !important;
    }

    /* Override any Bootstrap dropdown positioning restrictions */
    .dropdown-menu {
        position: absolute !important;
        z-index: 1040 !important;
        max-height: none !important;
        overflow: visible !important;
    }

    /* Ensure dropdowns show outside navbar bounds */
    .navbar .dropdown-menu {
        clip-path: none !important;
        clip: unset !important;
    }
}

/* Keep scrollbar only for notification dropdown which needs it */
.notification-dropdown {
    max-height: 400px !important;
    overflow-y: auto !important;
}


/* ===== ADMIN SETTINGS SELECT DROPDOWN FIXES ===== */
/* Force proper styling for admin settings select elements */
.settings-section select,
.settings-section .form-select,
#settingsForm select,
#settingsForm .form-select {
    background: var(--bg-tertiary) !important;
    border: 1px solid var(--border-color) !important;
    color: var(--text-color) !important;
    border-radius: var(--border-radius) !important;
    padding: 0.5rem 1rem !important;
    background-image: url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 16 16'%3e%3cpath fill='none' stroke='%23ffffff' stroke-linecap='round' stroke-linejoin='round' stroke-width='2' d='M2 5l6 6 6-6'/%3e%3c/svg%3e") !important;
    background-repeat: no-repeat !important;
    background-position: right 0.75rem center !important;
    background-size: 16px 12px !important;
    appearance: none !important;
    -webkit-appearance: none !important;
    -moz-appearance: none !important;
}

.settings-section select:focus,
.settings-section .form-select:focus,
#settingsForm select:focus,
#settingsForm .form-select:focus {
    background: var(--bg-tertiary) !important;
    border-color: var(--primary-color) !important;
    box-shadow: 0 0 0 0.2rem rgba(220, 53, 69, 0.25) !important;
    color: var(--text-color) !important;
    outline: none !important;
}

/* Options styling for select elements in admin */
.settings-section select option,
.settings-section .form-select option,
#settingsForm select option,
#settingsForm .form-select option {
    background-color: var(--bg-secondary) !important;
    color: var(--text-color) !important;
    padding: 0.5rem !important;
    border: none !important;
}

.settings-section select option:checked,
.settings-section .form-select option:checked,
#settingsForm select option:checked,
#settingsForm .form-select option:checked {
    background-color: var(--primary-color) !important;
    color: white !important;
}

.settings-section select option:hover,
.settings-section .form-select option:hover,
#settingsForm select option:hover,
#settingsForm .form-select option:hover {
    background-color: var(--bg-tertiary) !important;
    color: var(--text-color) !important;
}

/* Global select option fix for all browsers */
select option {
    background-color: var(--bg-secondary) !important;
    color: var(--text-color) !important;
}

select option:checked {
    background-color: var(--primary-color) !important;
    color: white !important;
}

/* For webkit browsers - additional fix */
@media screen and (-webkit-min-device-pixel-ratio:0) {
    select.form-select,
    select.form-control {
        background-color: var(--bg-tertiary) !important;
        color: var(--text-color) !important;
    }
}

