"""
معالج كشط الصور للمواقع المختلفة
يحل مشكلة التحقق من الصور المكشوطة في النظام
"""
import os

def check_scraped_images():
    """
    فحص الصور المكشوطة في المجلد المؤقت
    إرجاع: قائمة بأسماء الصور الموجودة
    """
    temp_scraped_dir = os.path.join('static', 'uploads', 'temp_scraped')
    scraped_images = []

    try:
        if os.path.exists(temp_scraped_dir):
            all_files = os.listdir(temp_scraped_dir)
            scraped_images = [
                f for f in all_files 
                if f.lower().endswith(('.jpg', '.jpeg', '.png', '.webp', '.gif'))
                and os.path.isfile(os.path.join(temp_scraped_dir, f))
            ]
            print(f"🔍 تم العثور على {len(scraped_images)} صورة مكشوطة في المجلد المؤقت")
            for img in scraped_images[:5]:  # عرض أول 5 صور
                print(f"  - {img}")
        else:
            print("📂 المجلد المؤقت للصور المكشوطة غير موجود")

    except Exception as e:
        print(f"⚠️ خطأ في فحص الصور المكشوطة: {e}")
        scraped_images = []

    return scraped_images

def perform_olympus_scraping(chapter_url):
    """
    كشط مباشر من موقع OlympusStaff
    """
    temp_scraped_dir = os.path.join('static', 'uploads', 'temp_scraped')

    try:
        # إنشاء المجلد وتنظيفه
        os.makedirs(temp_scraped_dir, exist_ok=True)

        # تنظيف المجلد من الصور القديمة
        for file in os.listdir(temp_scraped_dir):
            file_path = os.path.join(temp_scraped_dir, file)
            if os.path.isfile(file_path):
                os.remove(file_path)

        print(f"📥 بدء كشط الصور من OlympusStaff: {chapter_url}")

        # كشط الصور
        from olympustaff_scraper import scrape_olympustaff_enhanced, download_olympustaff_images
        scrape_result = scrape_olympustaff_enhanced(chapter_url)

        if scrape_result['success'] and scrape_result['images']:
            downloaded_images = download_olympustaff_images(
                scrape_result['images'], 
                temp_scraped_dir, 
                chapter_url
            )

            print(f"✅ تم كشط وحفظ {len(downloaded_images)} صورة بنجاح")
            return {
                'success': True,
                'images_count': len(downloaded_images),
                'chapter_title': scrape_result.get('chapter_title', 'غير محدد'),
                'message': f'تم حفظ {len(downloaded_images)} صورة'
            }
        else:
            error_msg = scrape_result.get('error', 'خطأ غير محدد في الكشط')
            print(f"❌ فشل في كشط الصور: {error_msg}")
            return {
                'success': False,
                'error': error_msg
            }

    except Exception as e:
        error_msg = f"خطأ في عملية الكشط: {str(e)}"
        print(f"❌ خطأ في perform_olympus_scraping: {error_msg}")
        return {
            'success': False,
            'error': error_msg
        }

def validate_scraped_images_for_upload():
    """
    التحقق من صحة الصور المكشوطة للرفع
    """
    scraped_images = check_scraped_images()

    if not scraped_images:
        return {
            'valid': False,
            'message': 'لم يتم العثور على صور مكشوطة. يرجى كشط الصور أولاً.',
            'images_count': 0
        }

    return {
        'valid': True,
        'message': f'تم العثور على {len(scraped_images)} صورة جاهزة للرفع',
        'images_count': len(scraped_images),
        'images': scraped_images
    }

simple_manga_scraper.py.content:
import os
import requests
from bs4 import BeautifulSoup
from urllib.parse import urljoin
import time
import random
import re

class SimpleMangaDownloader:
    def __init__(self):
        self.session = requests.Session()
        self.session.headers.update({
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36',
            'Referer': 'https://olympustaff.com/'
        })

    def scrape_and_download_chapter(self, chapter_url, output_folder):
        """
        كشط وتحميل فصل كامل - الطريقة المبسطة الموحدة
        """
        try:
            os.makedirs(output_folder, exist_ok=True)

            print(f"🔍 جاري كشط الفصل من: {chapter_url}")

            response = self.session.get(chapter_url)
            response.raise_for_status()

            soup = BeautifulSoup(response.text, 'html.parser')

            chapter_title = self.extract_chapter_title(soup)
            print(f"📖 عنوان الفصل: {chapter_title}")

            image_urls = self.extract_image_urls(soup)

            if not image_urls:
                print("❌ لم يتم العثور على أي صور في هذا الفصل!")
                return {
                    'success': False,
                    'error': 'لم يتم العثور على صور',
                    'chapter_title': chapter_title,
                    'images_found': 0,
                    'downloaded_files': []
                }

            print(f"✅ تم العثور على {len(image_urls)} صورة")

            # تحميل الصور بالترتيب
            downloaded_files = []
            for i, img_url in enumerate(image_urls):
                try:
                    print(f"⬇️ تحميل الصورة {i+1}/{len(image_urls)}")

                    img_response = self.session.get(img_url, stream=True, headers={'Referer': chapter_url})
                    img_response.raise_for_status()

                    # تحديد اسم الملف مع الترقيم الصحيح
                    file_extension = self.get_file_extension(img_url)
                    filename = f"page_{i+1:03d}{file_extension}"
                    img_path = os.path.join(output_folder, filename)

                    with open(img_path, 'wb') as f:
                        for chunk in img_response.iter_content(chunk_size=8192):
                            f.write(chunk)

                    # تحقق من حجم الملف
                    file_size = os.path.getsize(img_path)
                    if file_size > 1000:  # أكبر من 1KB
                        downloaded_files.append(img_path)
                        print(f"✅ تم تحميل: {filename} ({file_size} bytes)")
                    else:
                        print(f"⚠️ ملف صغير، سيتم حذفه: {filename}")
                        os.remove(img_path)

                    # تأخير عشوائي لتجنب الحظر
                    time.sleep(random.uniform(0.3, 1.0))

                except Exception as img_error:
                    print(f"❌ خطأ في تحميل الصورة {i+1}: {img_error}")

            print(f"🎯 تم تحميل {len(downloaded_files)} من أصل {len(image_urls)} صورة بنجاح")

            return {
                'success': True,
                'error': None,
                'chapter_title': chapter_title,
                'images_found': len(image_urls),
                'downloaded_files': downloaded_files
            }

        except Exception as e:
            print(f"❌ حدث خطأ: {e}")
            return {
                'success': False,
                'error': str(e),
                'chapter_title': None,
                'images_found': 0,
                'downloaded_files': []
            }

    def extract_chapter_title(self, soup):
        """استخراج عنوان الفصل"""
        title_tag = soup.find('h1', class_='entry-title')
        if title_tag:
            return title_tag.text.strip()

        # جرب محددات أخرى
        for selector in ['h1', 'h2', '.title', '.chapter-title']:
            title_element = soup.select_one(selector)
            if title_element:
                return title_element.get_text().strip()

        return "فصل غير معروف"

    def extract_image_urls(self, soup):
        """استخراج روابط الصور من الصفحة"""
        images = []

        # البحث في div.entry-content img كما في الكود المرفق
        img_containers = soup.select('div.entry-content img')

        for img in img_containers:
            img_url = img.get('src') or img.get('data-src') or img.get('data-original')
            if img_url and not img_url.startswith('data:'):
                # تحويل الروابط النسبية إلى مطلقة
                if 'olympustaff.com' not in img_url:
                    img_url = urljoin('https://olympustaff.com/', img_url)

                # تأكد من أن الرابط يحتوي على صورة
                if any(ext in img_url.lower() for ext in ['.jpg', '.jpeg', '.png', '.webp', '.gif']):
                    images.append(img_url)

        # إذا لم نجد صور في entry-content، جرب جميع الصور
        if not images:
            all_images = soup.find_all('img')
            for img in all_images:
                img_url = img.get('src') or img.get('data-src')
                if img_url and 'olympustaff.com' in img_url:
                    if any(ext in img_url.lower() for ext in ['.jpg', '.jpeg', '.png', '.webp', '.gif']):
                        images.append(img_url)

        # إزالة التكرارات مع الحفاظ على الترتيب
        unique_images = []
        seen_urls = set()
        for img_url in images:
            if img_url not in seen_urls:
                unique_images.append(img_url)
                seen_urls.add(img_url)

        return unique_images

    def get_file_extension(self, url):
        """تحديد امتداد الملف من الرابط"""
        if '.webp' in url.lower():
            return '.webp'
        elif '.png' in url.lower():
            return '.png'
        elif '.jpg' in url.lower() or '.jpeg' in url.lower():
            return '.jpg'
        else:
            return '.jpg'  # افتراضي

# دالة مساعدة للاستخدام في routes.py
def scrape_olympustaff_simple(chapter_url, output_folder):
    """
    دالة مبسطة لكشط وتحميل فصل من olympustaff
    """
    downloader = SimpleMangaDownloader()
    return downloader.scrape_and_download_chapter(chapter_url, output_folder)

def test_olympustaff_scraping(chapter_url):
    """
    دالة اختبار الكشط بدون تحميل للاستخدام في /admin/test-scrape
    """
    try:
        downloader = SimpleMangaDownloader()

        print(f"🧪 اختبار الكشط من: {chapter_url}")

        response = downloader.session.get(chapter_url)
        response.raise_for_status()

        soup = BeautifulSoup(response.text, 'html.parser')

        chapter_title = downloader.extract_chapter_title(soup)
        image_urls = downloader.extract_image_urls(soup)

        if not image_urls:
            return {
                'success': False,
                'error': 'لم يتم العثور على أي صور في هذا الفصل'
            }

        # إرجاع جميع الصور المكتشفة
        return {
            'success': True,
            'chapter_title': chapter_title or 'غير محدد',
            'total_images': len(image_urls),
            'sample_images': image_urls[:6],  # أول 6 صور للعرض السريع
            'all_images': image_urls  # جميع الصور للرفع الفعلي
        }

    except Exception as e:
        print(f"❌ خطأ في اختبار الكشط: {e}")
        return {
            'success': False,
            'error': f'خطأ في الاختبار: {str(e)}'
        }

# للاختبار المباشر
if __name__ == "__main__":
    downloader = SimpleMangaDownloader()

    chapter_url = input("الرجاء إدخال رابط الفصل الذي تريد تنزيله: ")
    output_folder = "downloads"

    result = downloader.scrape_and_download_chapter(chapter_url, output_folder)

    if result['success']:
        print(f"\n🎉 تم بنجاح!")
        print(f"📁 المجلد: {output_folder}")
        print(f"📄 الملفات المحملة: {len(result['downloaded_files'])}")
    else:
        print(f"\n💔 فشل: {result['error']}")

utils_seo.py.content:
"""
Advanced SEO utilities for comprehensive search engine optimization
"""

from flask import request, url_for
from utils_settings import SettingsManager
import re
import json
from urllib.parse import urljoin

def get_base_url():
    """Get base URL of the site dynamically"""
    try:
        if request:
            return request.url_root.rstrip('/')
    except RuntimeError:
        # Outside request context
        pass

    # Fallback to configured URL from settings
    configured_url = SettingsManager.get('site_url', None)
    if configured_url:
        return configured_url.rstrip('/')

    # Last resort fallback
    return 'https://example.com'

def generate_meta_title(page_title=None, page_type='page'):
    """Generate complete meta title with site branding"""
    site_title = SettingsManager.get('seo_site_title', 'منصة المانجا')
    separator = SettingsManager.get('seo_title_separator', ' | ')

    if page_title:
        if page_type == 'manga':
            return f"{page_title}{separator}قراءة مانجا{separator}{site_title}"
        elif page_type == 'chapter':
            return f"{page_title}{separator}قراءة الفصل{separator}{site_title}"
        elif page_type == 'category':
            return f"{page_title}{separator}تصنيف{separator}{site_title}"
        else:
            return f"{page_title}{separator}{site_title}"

    return site_title

def generate_meta_description(content=None, page_type='page', max_length=160):
    """Generate optimized meta description"""
    default_description = SettingsManager.get('seo_meta_description', 
                                              'منصة شاملة لقراءة المانجا والمانهوا باللغة العربية مجاناً')

    if not content:
        return default_description[:max_length]

    # Clean HTML tags
    clean_content = re.sub(r'<[^>]+>', '', str(content))
    clean_content = re.sub(r'\s+', ' ', clean_content).strip()

    # Add context based on page type
    if page_type == 'manga':
        prefix = "اقرأ "
        suffix = " مجاناً على منصة المانجا"
    elif page_type == 'chapter':
        prefix = "اقرأ الفصل "
        suffix = " مجاناً"
    else:
        prefix = ""
        suffix = ""

    full_description = prefix + clean_content + suffix

    # Truncate to max length
    if len(full_description) > max_length:
        return full_description[:max_length-3] + "..."

    return full_description

def generate_meta_keywords(custom_keywords=None, page_type='page'):
    """Generate meta keywords"""
    default_keywords = SettingsManager.get('seo_meta_keywords', 
                                          'مانجا, مانهوا, قراءة مانجا, مانجا عربية')

    keywords_list = [kw.strip() for kw in default_keywords.split(',') if kw.strip()]

    if custom_keywords:
        if isinstance(custom_keywords, str):
            custom_list = [kw.strip() for kw in custom_keywords.split(',') if kw.strip()]
        else:
            custom_list = [str(kw).strip() for kw in custom_keywords if str(kw).strip()]

        keywords_list.extend(custom_list)

    # Add contextual keywords based on page type
    if page_type == 'manga':
        keywords_list.extend(['قراءة مانجا اون لاين', 'مانجا مجانية'])
    elif page_type == 'chapter':
        keywords_list.extend(['فصل مانجا', 'قراءة فصل'])
    elif page_type == 'category':
        keywords_list.extend(['تصنيف مانجا', 'نوع مانجا'])

    # Remove duplicates while preserving order
    unique_keywords = []
    for kw in keywords_list:
        if kw not in unique_keywords:
            unique_keywords.append(kw)

    return ', '.join(unique_keywords[:15])  # Limit to 15 keywords

def generate_structured_data(manga=None, chapter=None):
    """Generate JSON-LD structured data for SEO"""
    import json

    if chapter and manga:
        # Chapter page structured data
        structured_data = {
            "@context": "https://schema.org",
            "@type": "Article",
            "headline": f"{manga.title} - Chapter {chapter.chapter_number}",
            "description": chapter.title or f"Chapter {chapter.chapter_number} of {manga.title}",
            "author": {
                "@type": "Person",
                "name": manga.author or "Unknown"
            },
            "publisher": {
                "@type": "Organization",
                "name": "Manga Platform"
            },
            "datePublished": chapter.created_at.isoformat() if chapter.created_at else "",
            "image": manga.cover_image if manga.cover_image else "",
            "url": f"/read/{manga.slug}/{chapter.slug}" if manga.slug and chapter.slug else "",
            "isPartOf": {
                "@type": "Series",
                "name": manga.title,
                "url": f"/manga/{manga.slug}" if manga.slug else ""
            }
        }
    elif manga:
        # Manga page structured data
        structured_data = {
            "@context": "https://schema.org",
            "@type": "ComicSeries",
            "name": manga.title,
            "description": manga.description or f"Read {manga.title} manga online",
            "author": {
                "@type": "Person",
                "name": manga.author or "Unknown"
            },
            "publisher": {
                "@type": "Organization",
                "name": "Manga Platform"
            },
            "dateCreated": manga.created_at.isoformat() if manga.created_at else "",
            "image": manga.cover_image if manga.cover_image else "",
            "url": f"/manga/{manga.slug}" if manga.slug else "",
            "genre": [cat.name for cat in manga.categories] if manga.categories else [],
            "numberOfEpisodes": manga.total_chapters,
            "aggregateRating": {
                "@type": "AggregateRating",
                "ratingValue": manga.average_rating,
                "ratingCount": len(manga.ratings.all()) if manga.ratings else 0
            } if manga.average_rating > 0 else None
        }
    else:
        # Default home page structured data
        structured_data = {
            "@context": "https://schema.org",
            "@type": "WebSite",
            "name": "Manga Platform",
            "description": "أفضل منصة لقراءة المانجا والمانهوا والمانهوا باللغة العربية مجاناً",
            "url": "/",
            "potentialAction": {
                "@type": "SearchAction",
                "target": "/search?q={search_term_string}",
                "query-input": "required name=search_term_string"
            }
        }

    return json.dumps(structured_data, ensure_ascii=False, indent=2)

def generate_meta_tags(title=None, description=None, image=None, url=None, manga=None, chapter=None):
    """Generate complete meta tags for SEO"""

    # Default values
    default_title = "Manga Platform - أفضل منصة لقراءة المانجا العربية"
    default_description = "اقرأ آلاف المانجا والمانهوا والمانهوا مجاناً باللغة العربية. تحديث يومي لأحدث الفصول."
    default_image = "/static/images/logo.png"

    # Set values based on context
    if manga and chapter:
        page_title = f"{manga.title} - الفصل {chapter.chapter_number}"
        if chapter.title:
            page_title += f" - {chapter.title}"
        page_description = f"اقرأ الفصل {chapter.chapter_number} من مانجا {manga.title} مجاناً. {chapter.title or ''}"
        page_image = manga.cover_image if manga.cover_image else default_image
        page_url = f"/read/{manga.slug}/{chapter.slug}" if manga.slug and chapter.slug else ""
    elif manga:
        page_title = f"{manga.title} - قراءة مانجا مجانية"
        page_description = generate_meta_description(manga.description) if manga.description else f"اقرأ مانجا {manga.title} مجاناً بجودة عالية. {manga.total_chapters} فصل متاح."
        page_image = manga.cover_image if manga.cover_image else default_image
        page_url = f"/manga/{manga.slug}" if manga.slug else ""
    else:
        page_title = title or default_title
        page_description = description or default_description
        page_image = image or default_image
        page_url = url or "/"

    return {
        'title': page_title,
        'description': page_description,
        'image': page_image,
        'url': page_url,
        'structured_data': generate_structured_data(manga, chapter)
    }

def generate_canonical_url(request, manga=None, chapter=None):
    """Generate canonical URL for the page"""
    base_url = request.url_root.rstrip('/')

    if manga and chapter and manga.slug and chapter.slug:
        return f"{base_url}/read/{manga.slug}/{chapter.slug}"
    elif manga and manga.slug:
        return f"{base_url}/manga/{manga.slug}"
    else:
        return request.url

def generate_breadcrumbs(manga=None, chapter=None):
    """Generate breadcrumb structured data"""
    import json

    breadcrumbs = [
        {
            "@type": "ListItem",
            "position": 1,
            "name": "الرئيسية",
            "item": "/"
        }
    ]

    if manga:
        breadcrumbs.append({
            "@type": "ListItem", 
            "position": 2,
            "name": manga.title,
            "item": f"/manga/{manga.slug}" if manga.slug else f"/manga/{manga.id}"
        })

        if chapter:
            breadcrumbs.append({
                "@type": "ListItem",
                "position": 3, 
                "name": f"الفصل {chapter.chapter_number}",
                "item": f"/read/{manga.slug}/{chapter.slug}" if manga.slug and chapter.slug else "#"
            })

    structured_breadcrumbs = {
        "@context": "https://schema.org",
        "@type": "BreadcrumbList",
        "itemListElement": breadcrumbs
    }

    return json.dumps(structured_breadcrumbs, ensure_ascii=False)

def generate_og_tags(title, description, image, url, page_type='website'):
    """Generate Open Graph meta tags"""
    if not SettingsManager.get('seo_og_enabled', True):
        return {}

    base_url = get_base_url()
    site_name = SettingsManager.get('site_name', 'منصة المانجا')

    og_tags = {
        'og:title': title,
        'og:description': description,
        'og:image': urljoin(base_url, image) if image else '',
        'og:url': urljoin(base_url, url) if url else base_url,
        'og:type': page_type,
        'og:site_name': site_name,
        'og:locale': 'ar_SA'
    }

    # Add Facebook App ID if configured
    fb_app_id = SettingsManager.get('seo_facebook_app_id')
    if fb_app_id:
        og_tags['fb:app_id'] = fb_app_id

    return og_tags

def generate_twitter_tags(title, description, image, url):
    """Generate Twitter Card meta tags"""
    if not SettingsManager.get('seo_twitter_enabled', True):
        return {}

    base_url = get_base_url()
    twitter_username = SettingsManager.get('seo_twitter_username', '')

    twitter_tags = {
        'twitter:card': 'summary_large_image',
        'twitter:title': title,
        'twitter:description': description,
        'twitter:image': urljoin(base_url, image) if image else ''
    }

    if twitter_username:
        twitter_tags['twitter:site'] = twitter_username if twitter_username.startswith('@') else f'@{twitter_username}'

    return twitter_tags

def generate_robots_meta():
    """Generate robots meta tag"""
    return SettingsManager.get('seo_robots_meta', 'index, follow')

def generate_preconnect_tags():
    """Generate preconnect link tags for performance"""
    if not SettingsManager.get('seo_page_speed_enabled', True):
        return []

    domains = SettingsManager.get('seo_preconnect_domains', '')
    if not domains:
        return []

    preconnect_tags = []
    for domain in domains.split(','):
        domain = domain.strip()
        if domain:
            preconnect_tags.append(f'https://{domain}' if not domain.startswith('http') else domain)

    return preconnect_tags

def generate_hreflang_tags(current_lang='ar'):
    """Generate hreflang tags for multilingual content"""
    if not SettingsManager.get('seo_hreflang_enabled', True):
        return {}

    base_url = get_base_url()
    current_path = request.path

    hreflang_tags = {
        'ar': f"{base_url}{current_path}",
        'en': f"{base_url}/en{current_path}" if current_path != '/' else f"{base_url}/en",
        'x-default': f"{base_url}{current_path}"  # Default for unknown locales
    }

    return hreflang_tags

def get_seo_analytics_code():
    """Get analytics tracking codes"""
    codes = {}

    # Google Analytics
    ga_id = SettingsManager.get('seo_google_analytics')
    if ga_id:
        codes['google_analytics'] = ga_id

    # Google Tag Manager
    gtm_id = SettingsManager.get('seo_google_tag_manager')
    if gtm_id:
        codes['google_tag_manager'] = gtm_id

    return codes

def get_custom_seo_code():
    """Get custom SEO code injections"""
    return {
        'head': SettingsManager.get('seo_custom_head', ''),
        'body_start': SettingsManager.get('seo_custom_body_start', ''),
        'body_end': SettingsManager.get('seo_custom_body_end', '')
    }

def generate_complete_seo_data(page_title=None, page_description=None, page_image=None, 
                              page_url=None, page_type='website', manga=None, chapter=None,
                              custom_keywords=None):
    """Generate complete SEO data for a page"""

    # Generate meta data
    meta_title = generate_meta_title(page_title, 'manga' if manga else 'chapter' if chapter else 'page')
    meta_description = generate_meta_description(page_description, 'manga' if manga else 'chapter' if chapter else 'page')
    meta_keywords = generate_meta_keywords(custom_keywords, 'manga' if manga else 'chapter' if chapter else 'page')

    # Determine final values
    final_title = meta_title
    final_description = meta_description
    final_image = page_image or manga.cover_image if manga else SettingsManager.get('seo_default_image')
    final_url = page_url or request.path

    # Generate all SEO components
    seo_data = {
        'meta': {
            'title': final_title,
            'description': final_description,
            'keywords': meta_keywords,
            'robots': generate_robots_meta()
        },
        'canonical_url': urljoin(get_base_url(), final_url) if SettingsManager.get('seo_canonical_enabled', True) else None,
        'og_tags': generate_og_tags(final_title, final_description, final_image, final_url, page_type),
        'twitter_tags': generate_twitter_tags(final_title, final_description, final_image, final_url),
        'hreflang_tags': generate_hreflang_tags(),
        'structured_data': generate_structured_data(manga, chapter) if SettingsManager.get('seo_schema_enabled', True) else None,
        'breadcrumbs': generate_breadcrumbs(manga, chapter) if SettingsManager.get('seo_breadcrumb_enabled', True) else None,
        'preconnect_domains': generate_preconnect_tags(),
        'analytics': get_seo_analytics_code(),
        'custom_code': get_custom_seo_code()
    }

    return seo_data

duplicate_analysis.py.content:
#!/usr/bin/env python3
"""
تحليل شامل للمشروع للعثور على التكرار والتضارب في الصفحات والمسارات
"""
import os
import re
from collections import defaultdict

def analyze_routes():
    """تحليل المسارات المكررة"""
    print("=== تحليل المسارات في routes.py ===")

    routes = {}
    duplicate_routes = defaultdict(list)

    with open('routes.py', 'r', encoding='utf-8') as f:
        content = f.read()

    # البحث عن جميع المسارات
    route_pattern = r"@app\.route\(['\"]([^'\"]+)['\"](?:,\s*methods=\[[^\]]+\])?\)\s*\n(?:@[\w_]+\s*\n)*def\s+(\w+)"
    matches = re.finditer(route_pattern, content, re.MULTILINE)

    for match in matches:
        route = match.group(1)
        function_name = match.group(2)

        if route in routes:
            duplicate_routes[route].append({
                'existing': routes[route],
                'new': function_name
            })
        else:
            routes[route] = function_name

    print(f"إجمالي المسارات: {len(routes)}")

    if duplicate_routes:
        print("\n⚠️ مسارات مكررة محتملة:")
        for route, duplicates in duplicate_routes.items():
            print(f"  {route}:")
            for dup in duplicates:
                print(f"    - {dup['existing']} / {dup['new']}")

    # البحث عن مسارات متشابهة
    similar_routes = []
    route_list = list(routes.keys())
    for i, route1 in enumerate(route_list):
        for route2 in route_list[i+1:]:
            if routes_are_similar(route1, route2):
                similar_routes.append((route1, route2, routes[route1], routes[route2]))

    if similar_routes:
        print("\n⚠️ مسارات متشابهة قد تسبب تضارب:")
        for route1, route2, func1, func2 in similar_routes:
            print(f"  {route1} ({func1}) <-> {route2} ({func2})")

    return routes, duplicate_routes, similar_routes

def routes_are_similar(route1, route2):
    """فحص إذا كانت المسارات متشابهة بشكل قد يسبب تضارب"""
    # إزالة أنواع البيانات من المتغيرات
    clean1 = re.sub(r'<[^>]+>', '<var>', route1)
    clean2 = re.sub(r'<[^>]+>', '<var>', route2)

    # مقارنة النمط العام
    pattern1 = clean1.replace('<var>', '.*')
    pattern2 = clean2.replace('<var>', '.*')

    return (re.match(pattern1, route2) or re.match(pattern2, route1)) and route1 != route2

def analyze_templates():
    """تحليل القوالب المكررة"""
    print("\n=== تحليل القوالب ===")

    template_files = []
    template_names = defaultdict(list)

    # جمع جميع ملفات HTML
    for root, dirs, files in os.walk('templates'):
        for file in files:
            if file.endswith('.html'):
                full_path = os.path.join(root, file)
                template_files.append(full_path)
                template_names[file].append(full_path)

    print(f"إجمالي ملفات القوالب: {len(template_files)}")

    # البحث عن أسماء مكررة
    duplicates = {name: paths for name, paths in template_names.items() if len(paths) > 1}

    if duplicates:
        print("\n⚠️ أسماء قوالب مكررة:")
        for name, paths in duplicates.items():
            print(f"  {name}:")
            for path in paths:
                print(f"    - {path}")

    return template_files, duplicates

def analyze_template_content():
    """تحليل محتوى القوالب للعثور على تكرار"""
    print("\n=== تحليل محتوى القوالب ===")

    template_content = {}
    content_hashes = defaultdict(list)

    for root, dirs, files in os.walk('templates'):
        for file in files:
            if file.endswith('.html'):
                full_path = os.path.join(root, file)
                try:
                    with open(full_path, 'r', encoding='utf-8') as f:
                        content = f.read()
                        template_content[full_path] = content

                        # حساب hash للمحتوى (تجاهل المسافات)
                        normalized = re.sub(r'\s+', ' ', content.strip())
                        content_hash = hash(normalized)
                        content_hashes[content_hash].append(full_path)
                except Exception as e:
                    print(f"خطأ في قراءة {full_path}: {e}")

    # البحث عن محتوى مطابق تماماً
    exact_duplicates = {h: paths for h, paths in content_hashes.items() if len(paths) > 1}

    if exact_duplicates:
        print("\n⚠️ قوالب بمحتوى مطابق:")
        for content_hash, paths in exact_duplicates.items():
            print(f"  المحتوى متطابق:")
            for path in paths:
                print(f"    - {path}")

    return exact_duplicates

def analyze_function_names():
    """تحليل أسماء الدوال المكررة"""
    print("\n=== تحليل أسماء الدوال ===")

    with open('routes.py', 'r', encoding='utf-8') as f:
        content = f.read()

    # البحث عن جميع تعريفات الدوال
    function_pattern = r"def\s+(\w+)\s*\("
    matches = re.findall(function_pattern, content)

    function_counts = defaultdict(int)
    for func in matches:
        function_counts[func] += 1

    duplicates = {name: count for name, count in function_counts.items() if count > 1}

    if duplicates:
        print("\n⚠️ أسماء دوال مكررة:")
        for name, count in duplicates.items():
            print(f"  {name}: {count} مرة")

    return duplicates

def check_route_function_mapping():
    """فحص تطابق المسارات مع الدوال"""
    print("\n=== فحص تطابق المسارات مع الدوال ===")

    with open('routes.py', 'r', encoding='utf-8') as f:
        content = f.read()

    # البحث عن المسارات والدوال المرتبطة
    route_function_pattern = r"@app\.route\(['\"]([^'\"]+)['\"](?:[^)]+)?\)\s*(?:@[\w_]+\s*)*\ndef\s+(\w+)"
    matches = re.findall(route_function_pattern, content, re.MULTILINE | re.DOTALL)

    route_to_functions = defaultdict(list)
    function_to_routes = defaultdict(list)

    for route, function in matches:
        route_to_functions[route].append(function)
        function_to_routes[function].append(route)

    # البحث عن مسارات مع دوال متعددة
    multi_function_routes = {route: funcs for route, funcs in route_to_functions.items() if len(funcs) > 1}

    if multi_function_routes:
        print("\n⚠️ مسارات مع دوال متعددة:")
        for route, functions in multi_function_routes.items():
            print(f"  {route}: {', '.join(functions)}")

    # البحث عن دوال مع مسارات متعددة
    multi_route_functions = {func: routes for func, routes in function_to_routes.items() if len(routes) > 1}

    if multi_route_functions:
        print("\n⚠️ دوال مع مسارات متعددة:")
        for function, routes in multi_route_functions.items():
            print(f"  {function}: {', '.join(routes)}")

    return multi_function_routes, multi_route_functions

def main():
    print("🔍 فحص المشروع للعثور على التكرار والتضارب\n")

    # تحليل المسارات
    routes, duplicate_routes, similar_routes = analyze_routes()

    # تحليل القوالب
    template_files, template_duplicates = analyze_templates()

    # تحليل محتوى القوالب
    content_duplicates = analyze_template_content()

    # تحليل أسماء الدوال
    function_duplicates = analyze_function_names()

    # فحص تطابق المسارات والدوال
    multi_function_routes, multi_route_functions = check_route_function_mapping()

    # ملخص النتائج
    print("\n" + "="*50)
    print("📊 ملخص التحليل:")

    issues_found = 0

    if duplicate_routes:
        print(f"⚠️ {len(duplicate_routes)} مسار مكرر")
        issues_found += len(duplicate_routes)

    if similar_routes:
        print(f"⚠️ {len(similar_routes)} مسار متشابه")
        issues_found += len(similar_routes)

    if template_duplicates:
        print(f"⚠️ {len(template_duplicates)} اسم قالب مكرر")
        issues_found += len(template_duplicates)

    if content_duplicates:
        print(f"⚠️ {len(content_duplicates)} قالب بمحتوى مطابق")
        issues_found += len(content_duplicates)

    if function_duplicates:
        print(f"⚠️ {len(function_duplicates)} اسم دالة مكرر")
        issues_found += len(function_duplicates)

    if multi_function_routes:
        print(f"⚠️ {len(multi_function_routes)} مسار مع دوال متعددة")
        issues_found += len(multi_function_routes)

    if multi_route_functions:
        print(f"⚠️ {len(multi_route_functions)} دالة مع مسارات متعددة")
        issues_found += len(multi_route_functions)

    if issues_found == 0:
        print("✅ لم يتم العثور على مشاكل تكرار واضحة")
    else:
        print(f"\n🚨 إجمالي المشاكل المحتملة: {issues_found}")
        print("يُنصح بمراجعة هذه النقاط لتجنب التضارب")

if __name__ == "__main__":
    main()

